import { prisma } from "@/lib/prisma";

export async function GET() {
  const restaurants = await prisma.restaurant.findMany();
  return NextResponse.json(restaurants);
}

export async function POST(req: Request) {
  const { name } = await req.json();
  const restaurant = await prisma.restaurant.create({ data: { name } });
  return NextResponse.json(restaurant);
}' />
  <str_replace_editor command="create" path="src/app/api/menu/route.ts" file_text='import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const restaurantId = searchParams.get("restaurantId") || "";
  const menuItems = await prisma.menuItem.findMany({ where: { restaurantId } });
  return NextResponse.json(menuItems);
}

export async function POST(req: Request) {
  const { name, price, restaurantId } = await req.json();
  const menuItem = await prisma.menuItem.create({ data: { name, price, restaurantId } });
  return NextResponse.json(menuItem);
}' />
  <str_replace_editor command="create" path="src/app/api/orders/route.ts" file_text='import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET() {
  const orders = await prisma.order.findMany({ include: { items: true } });
  return NextResponse.json(orders);
}

export async function POST(req: Request) {
  const { status, restaurantId } = await req.json();
  const order = await prisma.order.create({ data: { status, restaurantId } });
  return NextResponse.json(order);
}' />
