export default function MenuItemForm({ restaurantId }: { restaurantId: string }) {
  const [name, setName] = useState("");
  const [price, setPrice] = useState("");

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    await fetch("/api/menu", {
      method: "POST",
      body: JSON.stringify({ name, price: parseFloat(price), restaurantId }),
    });
  };

  return (
    <form onSubmit={handleSubmit} className="p-4 border rounded">
      <input value={name} onChange={(e) => setName(e.target.value)} placeholder="Name" className="border p-2" />
      <input value={price} onChange={(e) => setPrice(e.target.value)} placeholder="Price" className="border p-2" />
      <button type="submit" className="bg-blue-500 text-white p-2">Add Item</button>
    </form>
  );
}' />
